import{_ as t,c as o,o as i,ae as r}from"./chunks/framework.CDjunVez.js";const m=JSON.parse('{"title":"Download Remote File (Fetch URL)","description":"","frontmatter":{},"headers":[],"relativePath":"website/download.md","filePath":"website/download.md"}'),a={name:"website/download.md"};function s(n,e,l,d,c,h){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="download-remote-file-fetch-url" tabindex="-1">Download Remote File (Fetch URL) <a class="header-anchor" href="#download-remote-file-fetch-url" aria-label="Permalink to &quot;Download Remote File (Fetch URL)&quot;">​</a></h1><p>The File Manager includes a <strong>Fetch URL</strong> feature that lets you download files from a remote server directly into your website directory — equivalent to running <code>wget</code> or <code>curl</code> on the command line, but from the browser.</p><p>This is useful for installing CMS software (WordPress, Joomla, Laravel), restoring backups, pulling assets from CDNs, or downloading any publicly accessible file without needing SSH access.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li>Click the <strong>Fetch URL</strong> button in the file manager toolbar (the download-cloud icon next to Upload)</li><li>Enter the URL of the file you want to download</li><li>Optionally provide a custom filename (otherwise the original filename is used)</li><li>Click <strong>Download</strong> — the file is saved to your current directory</li></ol><p>A real-time progress bar shows download percentage, speed, and estimated time remaining for large files.</p><h2 id="limits" tabindex="-1">Limits <a class="header-anchor" href="#limits" aria-label="Permalink to &quot;Limits&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Limit</th><th>Value</th></tr></thead><tbody><tr><td>Maximum file size</td><td>10 GB</td></tr><tr><td>Download timeout</td><td>60 minutes</td></tr><tr><td>Concurrent downloads</td><td>3 per server</td></tr><tr><td>Supported protocols</td><td>HTTP and HTTPS only</td></tr><tr><td>Minimum free disk space</td><td>512 MB</td></tr></tbody></table><h2 id="filename-resolution" tabindex="-1">Filename Resolution <a class="header-anchor" href="#filename-resolution" aria-label="Permalink to &quot;Filename Resolution&quot;">​</a></h2><p>The downloaded file is named using the following priority:</p><ol><li><strong>Your custom filename</strong> — if you provide one in the &quot;Save as&quot; field</li><li><strong>Content-Disposition header</strong> — if the remote server suggests a filename</li><li><strong>URL path</strong> — the last segment of the URL (e.g., <code>wordpress-6.5.tar.gz</code> from <code>https://example.com/wordpress-6.5.tar.gz</code>)</li><li><strong>Fallback</strong> — <code>download</code> if no filename can be determined</li></ol><p>If a file with the same name already exists in the destination directory, it will be overwritten.</p><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><p>All downloads are subject to the following security checks:</p><ul><li><strong>Protocol restriction</strong> — Only <code>http://</code> and <code>https://</code> URLs are allowed. Protocols like <code>file://</code>, <code>ftp://</code>, and <code>gopher://</code> are blocked.</li><li><strong>SSRF protection</strong> — URLs that resolve to private or reserved IP addresses (localhost, <code>10.x.x.x</code>, <code>192.168.x.x</code>, etc.) are blocked to prevent Server-Side Request Forgery attacks. This includes IPv4-mapped IPv6 addresses.</li><li><strong>DNS pinning</strong> — DNS is resolved once before the connection is made, preventing DNS rebinding attacks.</li><li><strong>Redirect validation</strong> — Each redirect hop is checked for private IPs. Maximum 10 redirects.</li><li><strong>Filename sanitization</strong> — Path separators, <code>..</code> sequences, and control characters are stripped from filenames to prevent path traversal.</li><li><strong>Path validation</strong> — The destination directory must be within your home directory.</li></ul><div class="warning custom-block"><p class="custom-block-title">Important Caveats</p><ul><li><strong>Downloaded files are not scanned for malware.</strong> KiwiPanel does not inspect the content of downloaded files. You are responsible for ensuring that files you download are safe. Exercise the same caution you would when running <code>wget</code> on your server.</li><li><strong>Disk space is your responsibility.</strong> While KiwiPanel blocks downloads when free disk space drops below 512 MB, downloading large files can still consume significant disk space. Monitor your disk usage, especially on smaller VPS plans.</li><li><strong>Downloads count toward your bandwidth.</strong> The file is downloaded by your server, not your browser. The transfer uses your server&#39;s network bandwidth and may count against your hosting provider&#39;s bandwidth allocation.</li><li><strong>No resume support.</strong> If a download is interrupted (network error, timeout, browser tab closed), the partial file is automatically cleaned up. You will need to start the download again from scratch.</li><li><strong>Overwrite without warning.</strong> If a file with the same name already exists in the destination directory, it will be silently overwritten. Rename existing files first if you need to keep them.</li><li><strong>HTTPS certificates are validated.</strong> Downloads from servers with expired or self-signed SSL certificates will fail. This is intentional for your security.</li></ul></div>',16)])])}const f=t(a,[["render",s]]);export{m as __pageData,f as default};
